export const HiddenDarkMode = () => {
  const [clicks, setClicks] = useState(0);

  const handleClick = () => {
    setClicks(prev => {
      const newCount = prev + 1;
      if (newCount === 5) {
        document.documentElement.classList.toggle('dark');
        return 0;
      }
      return newCount;
    });
  };

  return (
